insert into oj.announcement (id, title, content, create_time, last_update_time, visible, created_by_id)
values  (1, '河北金融学院ccpc选拔赛', '<p>这是ccpc的选拔赛</p>', '2025-05-12 13:19:10.321358', '2025-05-12 13:30:55.398609', false, 1),
        (2, '这是主页公告', '<p>这是测试公告</p>', '2025-05-12 13:23:51.380666', '2025-05-12 13:23:51.380666', true, 1),
        (3, '这是一些比赛规则', '<p style="margin-left:0px;">ACM-ICPC以团队的形式代表各学校参赛，每队由至多3名队员组成。每位队员必须是在校学生，有一定的<a href="https://baike.baidu.com/item/%E5%B9%B4%E9%BE%84%E9%99%90%E5%88%B6/9416507?fromModule=lemma_inlink">年龄限制</a>，并且每年最多可以参加2站区域选拔赛。</p><p style="margin-left:0px;">比赛期间，每队使用1台电脑需要在5个小时内使用<a href="https://baike.baidu.com/item/C%2FC%2B%2B/6824246?fromModule=lemma_inlink">C/C++</a>、<a href="https://baike.baidu.com/item/Java/85979?fromModule=lemma_inlink">Java</a>和<a href="https://baike.baidu.com/item/Python/407313?fromModule=lemma_inlink">Python</a>中的一种编写程序解决7到13个问题。程序完成之后提交评测机运行，运行的结果会判定为正确或错误两种并及时通知参赛队。而且有趣的是每队在正确完成一题后，<a href="https://baike.baidu.com/item/%E7%BB%84%E7%BB%87%E8%80%85/3188042?fromModule=lemma_inlink">组织者</a>将在其位置上升起一只代表该题颜色的气球，每道题目第一支解决掉它的队还会额外获得一个“FIRST PROBLEM SOLVED”的气球。</p>', '2025-05-28 07:40:03.930675', '2025-05-28 07:40:03.930675', true, 1),
        (4, '这里有一些图片', '<p>&nbsp;</p><p>&nbsp;</p><figure class="image image-style-align-left image_resized" style="width:27.67%;"><img style="aspect-ratio:940/940;" src="/media/%E5%BE%AE%E4%BF%A1%E5%9B%BE%E7%89%87_20250528154425_kkOHukW.jpg" width="940" height="940"></figure><figure class="image image-style-align-left image_resized" style="width:26.58%;"><img style="aspect-ratio:940/940;" src="/media/%E5%BE%AE%E4%BF%A1%E5%9B%BE%E7%89%87_20250519201808_MgFsmYB.jpg" width="940" height="940"></figure><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p>', '2025-05-28 07:47:22.254075', '2025-05-28 07:47:22.254075', true, 1),
        (5, '2025年河北金融学研计算机程序设计竞赛参赛规则', '<p style="text-align:center;"><span style="font-family:黑体;font-size:20.0pt;"><strong>2025年度河北金融学院</strong></span></p><p style="text-align:center;"><span style="font-family:黑体;font-size:20.0pt;"><strong>计算机程序设计竞赛参赛规则</strong></span></p><p style="margin-left:32.2pt;"><span style="font-family:黑体;font-size:15.5pt;"><strong>一、参赛人员组成</strong></span></p><p style="margin-left:0cm;">(一)本比赛采取ACM赛制，团队赛，三人一组，不限专业，年级。</p><p>(二)参赛队员必须为我校在籍的本专科学生或硕士研究生。</p><p style="margin-left:32.7pt;"><span style="font-family:黑体;font-size:15.5pt;"><strong>二、活动组织</strong></span></p><p style="margin-left:0cm;">主办单位：信息与人工智能学院</p><p style="margin-left:0cm;">承办单位：校计算机协会、信息学院学生会</p><p style="margin-left:32.7pt;"><span style="font-family:黑体;font-size:15.5pt;"><strong>三、比赛规则</strong></span></p><p style="margin-left:0cm;">(一)竞赛题目为6-8题，比赛时间为3-4个小时。</p><p style="margin-left:0cm;">(二)参赛队员可以携带诸如书、手册、程序清单等纸质参考资料，但不能携带电子资料或浏览在线资料，如采用U盘携带程序或浏览网站、提问AI大模型。</p><p style="margin-left:0cm;">(三)试题的解答提交裁判称为运行，每一次运行会被判为正确或者错误，判决结果会及时通知选手个人。</p><p style="margin-left:0cm;">(四)根据解题数目进行排名，如果多个团队解题数量相同，则根据总用时加上惩罚时间进行排名。总用时和惩罚时间由每道解答正确的试题的用时加上惩罚时间组成。每道试题用时将从竞赛开始到试题解答被判定为正确为止，其间每一次错误的运行将被加罚，未正确解答的试题不计时 。</p><p><br>&nbsp;</p><p style="margin-left:0cm;">(五)竞赛语言支持C++&nbsp;、C&nbsp;、Java&nbsp;和 Python。</p><p style="margin-left:0cm;">(六)每个参赛团队共用一台计算机，任务提交后由服务器统一评测 。</p><p style="margin-left:32.7pt;"><span style="font-family:黑体;font-size:15.5pt;"><strong>四、比赛时间地点</strong></span></p><p style="margin-left:0cm;">比赛时间：2025年5月10日下午</p><p style="margin-left:0cm;">比赛地点：尚行楼机房</p><p style="margin-left:32.7pt;"><span style="font-family:黑体;font-size:15.5pt;"><strong>五、比赛奖励方式</strong></span></p><p style="margin-left:0cm;">比赛按照答题排名，评出一等奖，二等奖，三等奖若干，对同学们发放荣誉证书，进行公开表彰，同时将获奖情况在学院网站/公众号展示。具体比例可能会根据参赛人数或实际情况略有调整。</p><p style="margin-left:0cm;">一等奖：不超过参赛人数的10%，颁发荣誉证书。</p><p style="margin-left:0cm;">二等奖：不超过参赛人数的20%，颁发荣誉证书。</p><p style="margin-left:0cm;">三等奖：不超过参赛人数的30%，颁发荣誉证书。</p><p style="margin-left:0cm;">比赛将作为校内程序设计联赛在每年上下半年各举办一次，竞赛结果作为推荐参加下一年度CCPC河北省计算机程序设计竞赛的主要依据。</p>', '2025-05-28 08:09:31.699976', '2025-05-28 08:09:31.699976', true, 1),
        (6, '首页通知', '<p>本程序目前还处于测试阶段，禁止任何压测行为</p>', '2025-05-28 08:14:37.366871', '2025-05-28 08:14:37.366871', true, 1),
        (7, '关于AI的介绍', '<p>本AI基于本校应用的本地知识库搭建，可以让同学们搜索到学校竞赛，生活等一系列情况，欢迎大家提问。</p>', '2025-05-28 08:33:01.807019', '2025-05-28 08:33:01.807019', true, 1);